import os
import json

# Find all json files in the system
json_files = []
for root, dirs, files in os.walk('/tmp'):
    for file in files:
        if file.endswith('.json'):
            path = os.path.join(root, file)
            json_files.append(path)

print("Found JSON files:")
for f in json_files:
    print(f)

# Also check root temp directory
for root, dirs, files in os.walk('/'):
    if root.startswith('/tmp'):
        continue
    for file in files:
        if file.endswith('.json'):
            path = os.path.join(root, file)
            json_files.append(path)

print('\nLast 10 JSON files:')
print(json_files[-10:])

