import json
import os

# Load the UNIV CALIFORNIA patents data
path = '/tmp/query_db_32.json'
if os.path.exists(path):
    with open(path, 'r') as f:
        data = json.load(f)
    print('Loaded', len(data), 'UNIV CALIFORNIA patents')
    print('First patent info:', data[0]['Patents_info'][:100])
else:
    print('File not found at', path)
    # Try to find the file
    for root, dirs, files in os.walk('/tmp'):
        for file in files:
            if 'query_db_32' in file:
                print('Found file at:', os.path.join(root, file))

