# Try to find data files
for root, dirs, files in os.walk('/'):
    for file in files:
        if 'query_db_32' in file or 'UNIV' in file.upper():
            full_path = os.path.join(root, file)
            test_data['files'].append(full_path)
            if len(test_data['files']) >= 3:
                break
    if len(test_data['files']) >= 3:
        break

print('__RESULT__:')
print(json.dumps(test_data))

